<template>
	<view>
		
	
		
		<view class="image-preview" >
			<!-- 关闭按钮 -->

			<!-- 遮罩层 -->
			<!-- @click="closePreview" -->
			<!-- <view class="mask"></view> -->
			<!-- 图片展示区域 -->
			<swiper
			  :current="currentIndex"
			  @change="onSwiperChange"
			  circular
			  class="image-swiper"
			>
			  <swiper-item v-for="(image, index) in images" :key="index">
				<view class="image-container">
				  <image
					:src="image"
					mode="aspect-fit"
					:style="{
					  transform: `rotate(${rotateDegrees}deg) scale(${scale})`,
					  transformOrigin: 'center center'
					}"
					@touchstart="onTouchStart"
					@touchmove="onTouchMove"
					@touchend="onTouchEnd"
				  ></image>
				</view>
			  </swiper-item>
			</swiper>
			
			<view   style="position: absolute;top: 86px;">
				<view class="close-button" @click="closePreview">
				  ×
				</view>
				<!-- 下载按钮 -->
				<view class="download-button" style="width: 80rpx;" @click.stop="downloadImage">
				  下载
				</view>
			</view>
			<!-- 操作按钮 -->
			<view class="control-buttons">
				  <!-- 放大按钮，替换为图片 -->
				  <image
					src="/static/yw-preview/zoom_in.svg"
					mode="aspect-fit"
					@click="zoomIn"
					class="control-image"
				></image>
				 <!-- 缩小按钮，替换为图片 -->
				 <image
					src="/static/yw-preview/zoom_out.svg"
					mode="aspect-fit"
					class="control-image"
					@click="zoomOut"
				></image>
				 <!-- 右旋转按钮，替换为图片 -->
				 <image
					src="/static/yw-preview/rotate_right.svg"
					mode="aspect-fit"
					class="control-image"
					@click="rotateLeft"

				></image>
				<!-- 左旋转按钮，替换为图片 -->
				<image
					src="/static/yw-preview/rotate_left.svg"
					mode="aspect-fit"
					@click="rotateRight"
					class="control-image"
				></image>
			   
			  <!-- 全屏按钮，替换为图片 -->
			</view>
			<!-- 页码指示器 -->
			<view class="page-indicator">
			  {{ currentIndex + 1 }} / {{ images.length }}
			</view>
		</view>
	</view>
</template>

<script>
export default {
  props: {
    images: {
      type: Array,
      default: () => []
    },
    initialIndex: {
      type: Number,
      default: 0
    },
  },
  data() {
    return {
			statusBarHeight: uni.getSystemInfoSync ().statusBarHeight,//状态栏高度
			  currentIndex: this.initialIndex,
			  rotateDegrees: 0,
			  scale: 1,
			  isFullScreen: false,
			  startX: 0,
			  startY: 0,
			  startDistance: 0
    };
  },
  methods: {
    // 关闭预览
    closePreview() {
       this.$emit('close')
    },
    // 切换图片
    onSwiperChange(e) {
      this.currentIndex = e.detail.current;
    },
    // 左旋转图片
    rotateLeft() {
      this.rotateDegrees -= 90;
    },
    // 右旋转图片
    rotateRight() {
      this.rotateDegrees += 90;
    },
    // 放大图片
    zoomIn() {
      if (this.scale < 3) {
        this.scale += 0.1;
      }
    },
    // 缩小图片
    zoomOut() {
      if (this.scale > 0.5) {
        this.scale -= 0.1;
      }
    },
    // 切换全屏
    toggleFullScreen() {
      this.isFullScreen = !this.isFullScreen;
      if (this.isFullScreen) {
        // 进入全屏模式
        uni.setNavigationBarHidden({
          hidden: true,
          success: () => {
            // 可以添加更多样式调整代码
          },
          fail: (err) => {
            console.error('隐藏导航栏失败:', err);
          }
        });
      } else {
        // 退出全屏模式
        uni.setNavigationBarHidden({
          hidden: false,
          success: () => {
            // 可以添加更多样式调整代码
          },
          fail: (err) => {
            console.error('显示导航栏失败:', err);
          }
        });
      }
    },
    // 下载图片
    downloadImage() {
      console.log('开始下载图片'); // 添加日志输出
      const currentImage = this.images[this.currentIndex];
      uni.downloadFile({
        url: currentImage,
        success: (res) => {
          if (res.statusCode === 200) {
            uni.saveImageToPhotosAlbum({
              filePath: res.tempFilePath,
              success: () => {
                console.log('图片保存成功'); // 添加日志输出
                uni.showToast({
                  title: '下载成功',
                  icon: 'success'
                });
              },
              fail: (err) => {
                console.error('保存图片失败:', err);
                uni.showToast({
                  title: '保存失败',
                  icon: 'none'
                });
              }
            });
          } else {
            console.error('下载图片失败:', res.statusCode);
            uni.showToast({
              title: '下载失败',
              icon: 'none'
            });
          }
        },
        fail: (err) => {
          console.error('下载图片失败:', err);
          uni.showToast({
            title: '下载失败',
            icon: 'none'
          });
        }
      });
    },
    // 触摸开始事件
    onTouchStart(e) {
      if (e.touches.length === 2) {
        const dx = e.touches[1].clientX - e.touches[0].clientX;
        const dy = e.touches[1].clientY - e.touches[0].clientY;
        this.startDistance = Math.sqrt(dx * dx + dy * dy);
      } else {
        this.startX = e.touches[0].clientX;
        this.startY = e.touches[0].clientY;
      }
    },
    // 触摸移动事件
    onTouchMove(e) {
      if (e.touches.length === 2) {
        const dx = e.touches[1].clientX - e.touches[0].clientX;
        const dy = e.touches[1].clientY - e.touches[0].clientY;
        const currentDistance = Math.sqrt(dx * dx + dy * dy);
        const scaleChange = currentDistance / this.startDistance;
        this.scale *= scaleChange;
        this.startDistance = currentDistance;
      }
    },
    // 触摸结束事件
    onTouchEnd() {
      // 可以添加触摸结束后的逻辑
    }
  }
};
</script>

